const query = $input.first().json.query || {};
return [{
  json: {
    decision:     query.decision || 'Approved',
    employeeName: query.employeeName || 'Unknown',
    submittedAt:  query.submittedAt || ''
  }
}];

// Read the original request info
const requestData = $('Parse Approval Request').first().json;
const targetTimestamp = requestData.submittedAt;

// Search ALL rows from the sheet to find the matching one
const allRows = $input.all();
const matchedRow = allRows.find(item => item.json.submittedAt === targetTimestamp);

// Row not found at all
if (!matchedRow) {
  const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>Claim Not Found</title></head>
<body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center">
  <div style="max-width:460px;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)">
    <div style="font-size:72px;margin-bottom:16px">❓</div>
    <h1 style="color:#f59e0b;font-size:26px;margin:0 0 12px">Claim Not Found</h1>
    <p style="color:#555;font-size:15px">We couldn't find this claim in the database.</p>
    <p style="color:#999;font-size:12px;margin-top:16px">Ref: ${targetTimestamp}</p>
  </div>
</body></html>`;
  return [{ json: { locked: true, html, employeeName: requestData.employeeName, decision: requestData.decision } }];
}

// Check current status — if already decided, LOCK
const currentStatus = (matchedRow.json.claimStatus || '').trim();
const isDecided = currentStatus === 'Approved' || currentStatus === 'Rejected';

if (isDecided) {
  const emoji = currentStatus === 'Approved' ? '✅' : '❌';
  const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>Already Processed</title></head>
<body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center">
  <div style="max-width:460px;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)">
    <div style="font-size:72px;margin-bottom:16px">🔒</div>
    <h1 style="color:#6366f1;font-size:26px;margin:0 0 12px">Already Processed</h1>
    <p style="color:#555;font-size:15px;line-height:1.6;margin:0 0 24px">This claim has already been <strong>${currentStatus} ${emoji}</strong> and cannot be changed.</p>
    <div style="background:#f8f9fa;border:1px solid #eee;border-radius:10px;padding:16px 20px;text-align:left">
      <p style="margin:4px 0;font-size:13px;color:#444">👤 <strong>Employee:</strong> ${requestData.employeeName}</p>
      <p style="margin:4px 0;font-size:13px;color:#444">🏷 <strong>Final Status:</strong> ${currentStatus} ${emoji}</p>
    </div>
  </div>
</body></html>`;
  return [{ json: { locked: true, html, employeeName: requestData.employeeName, decision: currentStatus } }];
}

// Not decided yet — proceed with the update
return [{ json: { locked: false, employeeName: requestData.employeeName, decision: requestData.decision, submittedAt: requestData.submittedAt } }];

const data = $input.first().json;

// If this is a locked/already-processed response, the html is pre-built
if (data.locked && data.html) {
  return [{ json: { html: data.html } }];
}

// ALWAYS read decision + employeeName from the original webhook URL params
// This survives the Google Sheets update node which wipes those fields
const parsed = $('Parse Approval Request').first().json;
const decision     = parsed.decision     || 'Unknown';
const employeeName = parsed.employeeName || 'Unknown Employee';

const isApproved = decision === 'Approved';
const emoji   = isApproved ? '✅' : '❌';
const color   = isApproved ? '#10b981' : '#ef4444';
const bgColor = isApproved ? '#ecfdf5' : '#fef2f2';
const title   = isApproved ? 'Claim Approved!' : 'Claim Rejected';
const message = isApproved
  ? `The claim for <strong>${employeeName}</strong> has been <strong>approved</strong> successfully.`
  : `The claim for <strong>${employeeName}</strong> has been <strong>rejected</strong>.`;

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>${title}</title></head>
<body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center;box-sizing:border-box">
  <div style="max-width:460px;width:100%;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)">
    <div style="font-size:72px;margin-bottom:16px">${emoji}</div>
    <h1 style="color:${color};font-size:26px;margin:0 0 12px">${title}</h1>
    <p style="color:#555;font-size:15px;line-height:1.6;margin:0 0 24px">${message}</p>
    <div style="background:${bgColor};border:1px solid ${color}44;border-radius:10px;padding:16px 20px;text-align:left">
      <p style="margin:4px 0;font-size:13px;color:#444">👤 <strong>Employee:</strong> ${employeeName}</p>
      <p style="margin:4px 0;font-size:13px;color:#444">🏷 <strong>Decision:</strong> ${decision}</p>
    </div>
    <p style="margin-top:28px;color:#aaa;font-size:12px">The Claims Tracking Database has been updated automatically.</p>
  </div>
</body></html>`;

return [{ json: { html, decision, employeeName } }];
